code = """import json
import re

# Load all clinical records
clinical_result = locals()['var_functions.query_db:24']
if isinstance(clinical_result, str) and clinical_result.endswith('.json'):
    with open(clinical_result, 'r') as f:
        clinical_records = json.load(f)
else:
    clinical_records = clinical_result

# Extract all female BRCA patients with their barcodes and histological types
brca_patients = []
patient_barcode_pattern = r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}'

for record in clinical_records:
    patient_desc = record.get('Patient_description', '')
    
    # Look for TCGA barcode
    match = re.search(patient_barcode_pattern, patient_desc)
    if match and 'female' in patient_desc.lower():
        barcode = match.group(0)
        hist_type = record.get('histological_type', '')
        
        # Check if it's likely BRCA based on histological type or description
        desc_lower = patient_desc.lower()
        hist_lower = hist_type.lower()
        
        is_brca = False
        if ('brca' in desc_lower or 'breast' in desc_lower or 
            'ductal' in hist_lower or 'lobular' in hist_lower or 
            'mucinous carcinoma' in hist_lower or 'infiltrating' in hist_lower):
            is_brca = True
        
        if is_brca:
            brca_patients.append({
                'barcode': barcode,
                'histological_type': hist_type
            })

# Count by histological type
from collections import Counter
hist_type_counts = Counter([p['histological_type'] for p in brca_patients])

print('__RESULT__:')
print(json.dumps({
    'female_brca_patients': len(brca_patients),
    'histological_type_counts': dict(hist_type_counts.most_common()),
    'patient_barcodes': [p['barcode'] for p in brca_patients]
}, indent=2))"""

